            // Function to draw a line between two nodes
            function drawLine(startNodeId, endNodeId, className, svgElement, isCurved = true) {
                const start = getNodeCenter(startNodeId);
                const end = getNodeCenter(endNodeId);
                let pathData;
                if (isCurved) {
                    // Use a cubic bezier curve for a more organic feel
                    const controlPointFactor = 0.5; // Adjust for more/less curve
                    const cp1x = start.x + (end.x - start.x) * controlPointFactor;
                    const cp1y = start.y;
                    const cp2x = end.x - (end.x - start.x) * controlPointFactor;
                    const cp2y = end.y;
                    pathData = `M ${start.x} ${start.y} C ${cp1x} ${cp1y}, ${cp2x} ${cp2y}, ${end.x} ${end.y}`;
