                    pathData = `M ${start.x} ${start.y} L ${end.x} ${end.y}`;
                }
                const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
                path.setAttribute('d', pathData);
                path.setAttribute('class', `line ${className}`);
                svgElement.appendChild(path);
